INSERT INTO `mespcbdefect` VALUES (1, 'PCBA0001', 'PCBA0001missinghole', '缺孔', '指电路板上原本应存在的用于安装电子元器件或实现电气连接的孔没有被正确加工出来，可能由钻孔设备故障、钻孔程序错误或电路板定位不准确等原因导致，会影响元件安装和电气连接可靠性。', 0, '2025-10-28 16:19:11.000000', NULL);
INSERT INTO `mespcbdefect` VALUES (2, 'PCBA0001', 'PCBA0001mousebite', '鼠咬', '指电路板上的铜箔线路出现像被老鼠咬过一样的小缺口，通常由蚀刻工艺控制不当引起，如蚀刻液浓度不均匀、蚀刻时间过长或抗蚀层存在微小破损等，会增加线路电阻，影响信号传输。', 0, '2025-10-28 16:21:28.000000', NULL);
INSERT INTO `mespcbdefect` VALUES (3, 'PCBA0001', 'PCBA0001short', '短路', '短路缺陷，是指电路板上必须分开布线的两个或多个信号线或信号线与地线之间出现了不应有的电连接，可能由 PCB 板设计缺陷、制造质量问题、焊接质量问题等原因导致。', 0, '2025-10-28 16:22:23.000000', NULL);
INSERT INTO `mespcbdefect` VALUES (4, 'PCBA0001', 'PCBA0001opencircuit', '开路', '是指电路板上某一段电气路径断开，导致信号无法正常传输，通常在焊接或制造过程中产生，如焊接不良、机械损伤、化学腐蚀等都可能引发开路。\r\n是指电路板上某一段电气路径断开，导致信号无法正常传输，通常在焊接或制造过程中产生，如焊接不良、机械损伤、化学腐蚀等都可能引发开路。\r\n指电路板上某一段电气路径断开，导致信号无法正常传输，通常在焊接或制造过程中产生，如焊接不良、机械损伤、化学腐蚀等都可能引发开路。', 0, '2025-10-28 16:24:15.000000', NULL);
INSERT INTO `mespcbdefect` VALUES (5, 'PCBA0001', 'PCBA0001spur', '毛刺', '指电路板上出现的多余的铜箔突起，可能在钻孔、蚀刻或电镀等工艺过程中产生，如钻孔时钻头磨损或振动、蚀刻时溶液流动不均匀等，会干扰正常电路信号传输，严重时可能与相邻线路发生短路。', 0, '2025-10-28 16:25:17.000000', NULL);
INSERT INTO `mespcbdefect` VALUES (6, 'PCBA0001', 'PCBA0001spuriouscopper', '多余铜箔', '指电路板上出现了不应有的铜箔，可能是由于蚀刻不彻底、电镀过程中出现异常等原因导致，会影响电路板的电气性能和外观质量。', 0, '2025-10-28 16:26:04.000000', NULL);
INSERT INTO `mespcbdefect` VALUES (7, 'PCBA0001', 'nodefect', '无缺陷', '指没有缺陷', 0, '2025-11-29 23:56:32.000000', NULL);
